INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '5181f272-7a22-45be-bc15-c05cdee1b119',
  '00000000-0000-0000-0000-000000000001',
  $escape$Groq Function Calling — Structured Outputs at LPU Speed$escape$,
  $escape$Groq's OpenAI-compatible API means you can drop it in anywhere you'd use OpenAI — but the payoff is latency: Llama 3.3 70B on Groq returns tool calls in ~300ms vs. seconds elsewhere. Use `tool_choice: "required"` to force a tool call and guarantee structured output without a JSON-mode fallback. Define your schema as a JSON Schema function, then parse `response.choices[0].message.tool_calls[0].function.arguments` directly — it's already a JSON string. For strict structured outputs, pair this with Zod or Pydantic validation on your side; Groq doesn't enforce schema adherence server-side like OpenAI's `strict: true` mode. Note: Groq has no native embeddings endpoint — use a separate provider (e.g. `text-embedding-3-small` via OpenAI, or a local model) and store vectors in pgvector. The real Groq advantage is agentic loops: because each tool-call round-trip is so fast, you can run 5–10 LLM hops in the time a single GPT-4o call takes.$escape$,
  $escape$import Groq from 'groq-sdk';

const client = new Groq();

const response = await client.chat.completions.create({
  model: 'llama-3.3-70b-versatile',
  messages: [{ role: 'user', content: 'Get weather for London' }],
  tools: [{
    type: 'function',
    function: {
      name: 'get_weather',
      parameters: {
        type: 'object',
        properties: { city: { type: 'string' } },
        required: ['city'],
      },
    },
  }],
  tool_choice: 'required',
});

const args = JSON.parse(
  response.choices[0].message.tool_calls![0].function.arguments
);
console.log(args.city); // 'London'$escape$,
  $escape$typescript$escape$,
