INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'c849fe7c-c461-4d83-945b-e27866aa3844',
  '00000000-0000-0000-0000-000000000001',
  $escape$groq Parallel Tool Use — Fan Out, Collect, and Stream the Synthesis$escape$,
  $escape$Groq sets `parallel_tool_calls: true` by default on supported models, meaning the LLM emits multiple function calls in a single inference pass before your code executes any of them. This is the right primitive when a user query requires hitting several APIs simultaneously — no sequential chaining, no extra round trips. Pass your tools array as OpenAI-compatible JSON schemas; Groq validates them server-side. Use `tool_choice: "required"` to guarantee at least one call, or pass `{"type": "function", "function": {"name": "..."}}`to pin to a single tool. After executing your functions, push each result back as `{role: "tool", tool_call_id, content}` — order must match the original `tool_calls` array. For the final synthesis turn, enable `stream: true`; Groq's LPU throughput makes streaming feel instant even on `llama-3.3-70b-versatile`. Avoid streaming the tool-call turn itself — `delta.tool_calls[i].function.arguments` arrives as fragmented JSON you must manually accumulate, which adds fragility. Non-stream for tool collection, stream for the human-readable answer.$escape$,
  $escape$import Groq from "groq-sdk";

const client = new Groq();

const tools = [{
  type: "function" as const,
  function: {
    name: "get_repo_stats",
    parameters: { type: "object", properties: { repo: { type: "string" } }, required: ["repo"] }
  }
}];

const toolTurn = await client.chat.completions.create({
  model: "llama-3.3-70b-versatile",
  messages: [
    { role: "system", content: "You are a GitHub analysis assistant." },
    { role: "user",   content: "Compare vercel/next.js and facebook/react" }
  ],
  tools,
  tool_choice: "required",
  parallel_tool_calls: true,
});

const calls = toolTurn.choices[0].message.tool_calls ?? [];
const results = calls.map(c => ({
  role: "tool" as const,
  tool_call_id: c.id,
  content: JSON.stringify({ stars: Math.floor(Math.random() * 100000) })
}));

const stream = await client.chat.completions.create({
  model: "llama-3.3-70b-versatile",
  messages: [
    { role: "system",    content: "You are a GitHub analysis assistant." },
    { role: "user",     content: "Compare vercel/next.js and facebook/react" },
    toolTurn.choices[0].message,
    ...results
  ],
  stream: true,
});

for await (const chunk of stream) {
  process.stdout.write(chunk.choices[0]?.delta?.content ?? "");
}$escape$,
