INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '4ed00599-5b67-4d64-b630-abcbbb5fc953',
  '00000000-0000-0000-0000-000000000001',
  $escape$Groq's Inference Engine — Speed, Models, and OpenAI API Compatibility$escape$,
  $escape$Groq runs on Language Processing Units (LPUs), not GPUs. The architectural difference is stark: LPUs execute deterministic, single-tenant compute with no memory bandwidth contention, delivering 500–800 tokens/second on Llama 3.3 70B — roughly 10–25x faster than GPU-based providers at comparable model sizes.

Groq's GroqCloud currently supports: `llama-3.3-70b-versatile`, `llama-3.1-8b-instant`, `mixtral-8x7b-32768`, `gemma2-9b-it`, and `llama-guard-3-8b` for content moderation. The `32768` context models (Mixtral) are ideal for long-context retrieval without chunking overhead.

The API is OpenAI-compatible — swap the base URL and key, nothing else changes. This means any LangChain, LlamaIndex, or raw `openai` SDK integration works out of the box. Rate limits on free tier are aggressive (30 req/min for 70B), so cache aggressively and batch where possible. Use `stream: true` to start rendering before full completion — at Groq speeds, streaming is optional UX polish, not a necessity.$escape$,
  $escape$from groq import Groq

client = Groq(api_key="gsk_...")

response = client.chat.completions.create(
    model="llama-3.3-70b-versatile",
    messages=[{"role": "user", "content": "Explain RLHF in 3 sentences."}],
    temperature=0.2,
    max_tokens=256,
    stream=False,
)

print(response.choices[0].message.content)
print(f"Speed: {response.usage.completion_tokens / response.usage.total_time:.0f} tok/s")$escape$,
  $escape$python$escape$,
