INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'fa7c9916-61f7-40a3-abdc-87ecef7d2251',
  '00000000-0000-0000-0000-000000000001',
  $escape$Groq SDK + Ollama — Local Dev Without Switching Clients$escape$,
  $escape$Groq's cloud inference is fast, but every request sends your prompt to Groq's servers. For privacy-sensitive prototyping — PII-heavy prompts, proprietary codebases, client data — Ollama lets you run the same model families locally with zero egress. The key insight: Ollama exposes an OpenAI-compatible REST endpoint at `http://localhost:11434/v1`, which means the `groq` Python SDK can point directly at it by overriding `base_url`. You keep the same client interface, the same message schema, the same response shape — just pass `api_key="ollama"` (Ollama ignores it) and reference a locally-pulled model.

Ollama's library ships quantized GGUF variants of Llama 3.2, Mistral, Gemma 2, and others — the same families Groq serves on-cloud. Pull with `ollama pull llama3.2`, prototype locally, then restore `base_url` and your real Groq API key to hit Groq's LPU infrastructure for sub-200ms production latency. Your CI gets deterministic offline tests; your prod path gets Groq's speed. No client code changes between environments.$escape$,
  $escape$from groq import Groq

# Dev: redirect Groq client to local Ollama instance
client = Groq(
    base_url="http://localhost:11434/v1",
    api_key="ollama",  # Ollama ignores this value
)

response = client.chat.completions.create(
    model="llama3.2",  # ollama pull llama3.2
    messages=[{"role": "user", "content": "Explain GGUF quantization briefly."}],
)
print(response.choices[0].message.content)

# Production: swap back to Groq endpoint + real key — zero other changes needed$escape$,
  $escape$python$escape$,
