INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '2e9ec15a-7974-49e2-a5b6-2ee1462ba6fe',
  '00000000-0000-0000-0000-000000000001',
  $escape$Groq RAG Pipelines — Solving the Embedding Gap$escape$,
  $escape$Groq's API is inference-only — there are no native embedding endpoints. Every RAG pipeline built on Groq needs a deliberate embedding strategy. The standard pattern: use sentence-transformers locally (all-MiniLM-L6-v2, 384-dim) or a remote provider like OpenAI's text-embedding-3-small (1536-dim) for retrieval, then hand off to Groq's Llama 3.3 70B for generation. Latency math matters here: Groq delivers sub-100ms LLM responses, but a remote embedding call adds 50–150ms — easily dominating your pipeline. Local MiniLM inference costs ~5ms on CPU and scores ~63.0 on MTEB, nearly matching text-embedding-3-small's ~62.3. For cosine similarity, normalize vectors before dot product — faster and numerically stable. Store vectors in pgvector with an HNSW index (m=16, ef_construction=64) for sub-10ms ANN retrieval. The optimal Groq RAG stack: sentence-transformers local embed → pgvector HNSW lookup → Groq LLaMA generation. This keeps your total round-trip under 200ms, fully exploiting Groq's inference speed advantage.$escape$,
  $escape$from sentence_transformers import SentenceTransformer
from groq import Groq
import numpy as np

embedder = SentenceTransformer("all-MiniLM-L6-v2")
client = Groq()

def rag_query(question: str, docs: list[str]) -> str:
    q_vec = embedder.encode(question, normalize_embeddings=True)
    doc_vecs = embedder.encode(docs, normalize_embeddings=True)
    scores = doc_vecs @ q_vec
    top_doc = docs[np.argmax(scores)]

    response = client.chat.completions.create(
        model="llama-3.3-70b-versatile",
        messages=[
            {"role": "system", "content": f"Context: {top_doc}"},
            {"role": "user", "content": question},
        ],
    )
    return response.choices[0].message.content$escape$,
  $escape$python$escape$,
