INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '0106a543-90e1-4672-a9a3-78260a432a67',
  '00000000-0000-0000-0000-000000000001',
  $escape$Groq Fine-Tuning vs Prompt Engineering — When LPU Speed Changes the Calculus$escape$,
  $escape$Groq's LPU delivers ~500 tokens/sec — that changes the fine-tune vs prompt-engineer decision tree. Latency is no longer a reason to compress behavior into fine-tuned weights; you can afford 50-shot examples in-context and still respond faster than GPU-hosted fine-tuned models.

**Stick with prompt engineering when:** your dataset is under 500 examples, task format varies, or you need rapid iteration. On Groq, a rich system prompt with dynamic few-shots costs milliseconds, not seconds.

**Fine-tune when:** you need consistent structured output the model resists (strict JSON schemas, proprietary formats), domain vocabulary is highly specialized, or you're hitting token budget ceilings at scale. Target 1,000+ labeled examples before committing.

**LoRA / QLoRA:** LoRA freezes base weights and trains low-rank adapter matrices (rank 8–64). QLoRA adds 4-bit NF4 quantization so a 70B model fits on a single A100. Use `unsloth` or `trl`'s `SFTTrainer` for fast runs.

Critical caveat: Groq is inference-only. Fine-tuned models must be deployed elsewhere — vLLM, Together AI, or self-hosted. Groq will not serve your LoRA adapter. This makes prompt engineering on `llama-3.3-70b-versatile` your primary lever inside Groq's ecosystem.$escape$,
  $escape$from groq import Groq

client = Groq()

# Exhaust few-shot prompting before committing to fine-tuning
def classify_intent(user_msg: str, examples: list[dict]) -> str:
    messages = [
        {"role": "system", "content": "Classify intent as: bug_report | feature_request | question"},
        *[msg for ex in examples for msg in [
            {"role": "user", "content": ex["input"]},
            {"role": "assistant", "content": ex["label"]}
        ]],
        {"role": "user", "content": user_msg}
    ]
    resp = client.chat.completions.create(
        model="llama-3.3-70b-versatile",
        messages=messages,
        temperature=0,
        max_tokens=10
    )
    return resp.choices[0].message.content$escape$,
  $escape$python$escape$,
