INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '3265b306-2f74-4062-92f0-0457a61343ee',
  '00000000-0000-0000-0000-000000000001',
  $escape$Groq Tool Use — Building Fast Agent Loops with Function Calling$escape$,
  $escape$Groq's sub-100ms inference latency fundamentally changes agent loop economics. Each ReAct cycle (Reason → Act → Observe) that would take 2–3s on slower providers completes in ~300ms on Groq, making multi-step agents actually usable in real-time UX.

Groq's function calling follows the OpenAI-compatible schema: pass `tools` as an array of JSON Schema definitions, then check `response.choices[0].message.tool_calls`. If `finish_reason === 'tool_calls'`, execute the tool, append the result as a `role: 'tool'` message, and re-invoke — the agent loop.

Key Groq-specific behavior: `llama-3.3-70b-versatile` is the strongest tool-use model on Groq. Set `tool_choice: 'auto'` to let the model decide, or `{ type: 'function', function: { name } }` to force a specific tool. Avoid `parallel_tool_calls: true` unless your tools are truly independent — Groq supports it, but llama-3.3 can hallucinate argument overlap in parallel calls. Cap agent loops at 5–8 iterations with a hard counter to prevent runaway token burn.$escape$,
  $escape$import Groq from 'groq-sdk';

const client = new Groq();
const tools = [{ type: 'function', function: { name: 'get_price', description: 'Fetch current token price', parameters: { type: 'object', properties: { symbol: { type: 'string' } }, required: ['symbol'] } } }];
const messages = [{ role: 'user', content: 'What is the current price of ETH?' }];

for (let i = 0; i < 5; i++) {
  const res = await client.chat.completions.create({ model: 'llama-3.3-70b-versatile', messages, tools, tool_choice: 'auto' });
  const msg = res.choices[0].message;
  if (res.choices[0].finish_reason !== 'tool_calls') { console.log(msg.content); break; }
  messages.push(msg);
  for (const call of msg.tool_calls) {
    const result = call.function.name === 'get_price' ? { price: 3200 } : {};
    messages.push({ role: 'tool', tool_call_id: call.id, content: JSON.stringify(result) });
  }
}$escape$,
  $escape$typescript$escape$,
