INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '954d84f6-24c5-4fd3-a678-119344fe148b',
  '00000000-0000-0000-0000-000000000001',
  $escape$Groq Streaming — Token-by-Token Output with chat.completions.create$escape$,
  $escape$Groq's inference speed (often 500+ tokens/sec) makes streaming feel instantaneous, but you still want it — streaming unblocks your UI immediately rather than waiting for a full response buffer. Pass `stream: true` to `client.chat.completions.create()` and you get back an async iterable of `ChatCompletionChunk` objects. Each chunk carries `choices[0].delta.content`, which is `null` on the final chunk when `finish_reason` is set. For UX, append each delta directly to a `ref` (not state) to avoid React re-render thrashing — flush to state every ~50ms with a `setInterval`. Groq supports streaming across all hosted models including `llama-3.3-70b-versatile` and `mixtral-8x7b-32768`. One gotcha: if you're using `tool_calls`, the delta accumulates across chunks — you must concatenate `delta.tool_calls[0].function.arguments` manually before parsing JSON. Abort mid-stream via `AbortController` passed as `signal` in the fetch options, or by breaking out of the async iterator early, which triggers `stream.controller.abort()` automatically.$escape$,
  $escape$import Groq from "groq-sdk";

const client = new Groq();

const stream = await client.chat.completions.create({
  model: "llama-3.3-70b-versatile",
  messages: [{ role: "user", content: "Explain RLHF in 3 sentences" }],
  stream: true,
});

for await (const chunk of stream) {
  const delta = chunk.choices[0]?.delta?.content ?? "";
  process.stdout.write(delta);
  if (chunk.choices[0]?.finish_reason === "stop") break;
}$escape$,
  $escape$typescript$escape$,
