INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '9dab2b4c-f784-4e22-a0ef-25995bf78bbf',
  '00000000-0000-0000-0000-000000000001',
  $escape$Groq Cost Management — Token Counting, Model Routing, and Batching$escape$,
  $escape$Groq bills input and output tokens separately — output tokens cost more, so cap every request with `max_tokens`. Every `ChatCompletion` response exposes `response.usage` with `prompt_tokens`, `completion_tokens`, and `total_tokens`; log these per call to catch prompt bloat before it compounds.

The highest-leverage cost lever is model routing. Use `llama-3.1-8b-instant` (131K context, ~$0.05/M input) for classification, extraction, and short summaries. Reserve `llama-3.3-70b-versatile` for multi-step reasoning or RAG synthesis. A simple dispatcher keyed on task type can cut costs 60–80% on mixed workloads.

Groq has no native batch endpoint, so parallelize with the async client: `AsyncGroq` + `asyncio.gather()` lets you fire concurrent requests while respecting rate limits (free tier: 30 RPM on most models; paid: up to 14,400 RPD on 70B). Groq does not currently offer prompt caching, so trim static system prompts aggressively — every token repeated across thousands of calls is a direct cost multiplier. Inject dynamic context via the `user` role instead of bloating the `system` prompt.$escape$,
  $escape$import asyncio
from groq import AsyncGroq

client = AsyncGroq()

ROUTING = {
    "simple": "llama-3.1-8b-instant",
    "complex": "llama-3.3-70b-versatile",
}

async def chat(prompt: str, task_type: str = "simple") -> str:
    response = await client.chat.completions.create(
        model=ROUTING[task_type],
        messages=[{"role": "user", "content": prompt}],
        max_tokens=512,
    )
    u = response.usage
    print(f"[{ROUTING[task_type]}] in={u.prompt_tokens} out={u.completion_tokens} total={u.total_tokens}")
    return response.choices[0].message.content

async def batch(prompts: list[str]) -> list[str]:
    return await asyncio.gather(*[chat(p) for p in prompts])$escape$,
  $escape$python$escape$,
