INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'd798295a-c9f8-4c95-992e-63e120c40ae1',
  '00000000-0000-0000-0000-000000000001',
  $escape$Groq Safety Guardrails — Llama Guard, Prompt Injection, and Hallucination Mitigation$escape$,
  $escape$Groq hosts Llama Guard 3 (`llama-guard-3-8b`) as a first-class model — use it as an async moderation layer without adding meaningful latency, since Groq's inference speed keeps the round-trip under 200ms. Call it after generation to classify outputs across 14 hazard categories (S1–S14), then gate your response on the result.

For prompt injection, Groq recommends structuring system prompts with explicit trust delimiters: wrap user input in XML-style tags (`<user_input>`) and instruct the model to treat content inside them as untrusted data only. This survives most direct injection attempts against Llama 3.3 70B.

Hallucination mitigation on Groq leans on `temperature: 0` plus `logprobs: true` — expose token-level confidence and reject answers where top-token probability drops below a threshold (e.g. < 0.6) on factual queries. Combine with a retrieval step: pass only grounded context in the system prompt and explicitly instruct the model not to answer outside it. The `stop` parameter can hard-terminate responses that drift past a known sentinel.$escape$,
  $escape$import Groq from 'groq-sdk';

const groq = new Groq();

async function safeCompletion(userMessage: string): Promise<string | null> {
  const response = await groq.chat.completions.create({
    model: 'llama-3.3-70b-versatile',
    temperature: 0,
    logprobs: true,
    messages: [
      { role: 'system', content: 'Answer only from provided context. Do not speculate.' },
      { role: 'user', content: `<user_input>${userMessage}</user_input>` },
    ],
  });

  const choice = response.choices[0];
  const minProb = Math.min(
    ...(choice.logprobs?.content?.map(t => Math.exp(t.logprob)) ?? [1])
  );
  if (minProb < 0.6) return null; // low-confidence — reject

  const guard = await groq.chat.completions.create({
    model: 'llama-guard-3-8b',
    messages: [{ role: 'user', content: choice.message.content ?? '' }],
  });

  return guard.choices[0].message.content?.startsWith('safe') ? choice.message.content : null;
}$escape$,
  $escape$typescript$escape$,
