INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '9438d4bb-dac5-49b8-b488-546d8ed1678d',
  '00000000-0000-0000-0000-000000000001',
  $escape$Groq Context Management — Sliding Window and Chunking for 128k Token Models$escape$,
  $escape$Groq's fastest models vary wildly in context limits: `llama-3.3-70b-versatile` and `llama-3.1-8b-instant` support 128k tokens, while `mixtral-8x7b-32768` caps at 32k. Exceeding these silently truncates or raises a 400. For chat apps, implement a sliding window over `messages[]` — keep the system prompt, drop oldest user/assistant pairs until you're under budget. Track tokens using Groq's `usage.prompt_tokens` from the response object, not a local estimator. For document Q&A, chunk at ~3,000 tokens with 200-token overlap, embed each chunk, retrieve top-k by similarity, then pass only those chunks to Groq. When conversation history itself grows beyond budget, use a summarization pass: send the oldest N turns to `llama-3.1-8b-instant` (fast, cheap) and replace them with a single summary message. Always set `max_tokens` explicitly — Groq won't auto-cap output, and runaway completions eat your remaining context budget. Monitor `x-ratelimit-remaining-tokens` in response headers to avoid hitting TPM limits mid-session.$escape$,
  $escape$from groq import Groq

client = Groq()
MAX_CONTEXT = 120_000  # leave headroom under 128k

def sliding_window(messages: list[dict], limit: int = MAX_CONTEXT) -> list[dict]:
    system = [m for m in messages if m["role"] == "system"]
    history = [m for m in messages if m["role"] != "system"]
    # rough token estimate: 1 token ≈ 4 chars
    while sum(len(m["content"]) // 4 for m in system + history) > limit:
        history = history[2:]  # drop oldest user+assistant pair
    return system + history

response = client.chat.completions.create(
    model="llama-3.3-70b-versatile",
    messages=sliding_window(conversation_history),
    max_tokens=1024,
)
print(response.usage.prompt_tokens)  # verify actual token usage$escape$,
  $escape$python$escape$,
